  image_caption: message.image?.caption || null,
  latitude: message.location?.latitude || null,
  longitude: message.location?.longitude || null,
  timestamp: message.timestamp,
  skip: false
} }];

// ============================================
// SESSION MANAGER v7 - Upstash Redis Persistence
// Works in test webhook mode
// ============================================

const UPSTASH_URL = 'https://clever-seal-100902.upstash.io';
const UPSTASH_TOKEN = 'gQAAAAAAAYomAAIocDIwY2E4MDY1ZmVkMWQ0M2ZhODM0ZWQ1OTZmODI5OGEyZHAyMTAwOTAy';
const PHOTO_REQUIRED = ['Pothole', 'Waterlogging', 'Garbage', 'Flooding', 'Road Blockage', 'Sewage Overflow', 'Water Leakage', 'Construction Hazard', 'Live Wire'];

const data = $input.first().json;
const phone = data.phone;
const sessionKey = 'civix_session_' + phone;

// ---- Helper: Get session from Upstash ----
async function getSession() {
  try {
    const res = await $http.request({
      method: 'GET',
      url: `${UPSTASH_URL}/get/${sessionKey}`,
      headers: { 'Authorization': `Bearer ${UPSTASH_TOKEN}` }
    });
    const body = typeof res === 'string' ? JSON.parse(res) : res;
    if (body.result && body.result !== null) {
      return JSON.parse(body.result);
    }
    return null;
  } catch(e) {
    return null;
  }
}

// ---- Helper: Save session to Upstash (TTL 1 hour) ----
async function saveSession(sessionData) {
  try {
    await $http.request({
      method: 'POST',
      url: `${UPSTASH_URL}/set/${sessionKey}`,
      headers: { 'Authorization': `Bearer ${UPSTASH_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ value: JSON.stringify(sessionData), ex: 3600 })
    });
  } catch(e) {}
}

// ---- Helper: Delete session from Upstash ----
async function deleteSession() {
  try {
    await $http.request({
      method: 'GET',
      url: `${UPSTASH_URL}/del/${sessionKey}`,
      headers: { 'Authorization': `Bearer ${UPSTASH_TOKEN}` }
    });
  } catch(e) {}
}

// ============================================
// MAIN LOGIC
// ============================================
const session = await getSession();

// ==========================================
// NO ACTIVE SESSION
// ==========================================
if (!session) {
  if (data.message_type === 'location') {
    return [{ json: { ...data, chat_action: 'orphan_location' } }];
  }
  if (data.message_type === 'text' && data.text && data.text.trim().split(/\s+/).length < 3) {
    return [{ json: { ...data, chat_action: 'spam' } }];
  }
  return [{ json: { ...data, chat_action: 'new_complaint' } }];
}

// ==========================================
// PHASE: awaiting_location
// ==========================================
if (session.phase === 'awaiting_location') {
  if (data.message_type === 'location') {
    session.partial_pulse.location.latitude = data.latitude;
    session.partial_pulse.location.longitude = data.longitude;
    session.partial_pulse.location.source = 'native_pin';
    const needsPhoto = PHOTO_REQUIRED.includes(session.partial_pulse.ai_analysis.issue_type);
    if (needsPhoto) {
      session.phase = 'awaiting_photo';
      await saveSession(session);
      return [{ json: { phone: data.phone, name: data.name, issue_type: session.partial_pulse.ai_analysis.issue_type, chat_action: 'ask_photo' } }];
    } else {
      const pulse = { ...session.partial_pulse, chat_action: 'complete' };
      await deleteSession();
      return [{ json: pulse }];
    }
  }
  if (data.message_type === 'text' && data.text) {
    session.partial_pulse.location.provided_text = data.text;
    session.partial_pulse.location.geocode_query = data.text + ', Hyderabad, India';
    const needsPhoto = PHOTO_REQUIRED.includes(session.partial_pulse.ai_analysis.issue_type);
    if (needsPhoto) {
      session.phase = 'awaiting_photo';
      await saveSession(session);
      return [{ json: { phone: data.phone, name: data.name, issue_type: session.partial_pulse.ai_analysis.issue_type, chat_action: 'ask_photo' } }];
    } else {
      const pulse = { ...session.partial_pulse, chat_action: 'geocode_then_complete' };
      await deleteSession();
      return [{ json: pulse }];
    }
  }
  return [{ json: { phone: data.phone, name: data.name, chat_action: 'remind_location' } }];
}

// ==========================================
// PHASE: awaiting_photo
// ==========================================
if (session.phase === 'awaiting_photo') {
  if (data.message_type === 'image') {
    session.partial_pulse.multimodal_urls.image_url = 'https://graph.facebook.com/v19.0/' + data.image_id;
    const pulse = { ...session.partial_pulse, chat_action: 'complete' };
    await deleteSession();
    return [{ json: pulse }];
  }
  if (data.message_type === 'text' && data.text && data.text.toLowerCase().trim() === 'skip') {
    const pulse = { ...session.partial_pulse, chat_action: 'complete' };
    await deleteSession();
    return [{ json: pulse }];
  }
  return [{ json: { phone: data.phone, name: data.name, chat_action: 'remind_photo' } }];
}

return [{ json: { ...data, chat_action: 'new_complaint' } }];

const binaryData = $input.first().binary?.data;
