// Build Partial Pulse + Save to Upstash
const UPSTASH_URL = 'https://clever-seal-100902.upstash.io';
const UPSTASH_TOKEN = 'gQAAAAAAAYomAAIocDIwY2E4MDY1ZmVkMWQ0M2ZhODM0ZWQ1OTZmODI5OGEyZHAyMTAwOTAy';

const classifyOutput = $input.first().json;
const rawData = $('Extract Message Data').first().json;

let ai;
try {
  ai = JSON.parse(classifyOutput.choices[0].message.content.replace(/```json|```/g,'').trim());
} catch(e) {
  ai = { translated_description: 'Unable to parse', domain: 'MUNICIPAL', issue_type: 'Unknown', sentiment_score: 5, panic_flag: false, location_hint: '', needs_photo: false };
}

const uuid = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r=Math.random()*16|0; return (c==='x'?r:(r&0x3|0x8)).toString(16); });

const partialPulse = {
  event_id: uuid(),
  timestamp: new Date().toISOString(),
  source: 'whatsapp',
  citizen_id: rawData.phone,
  citizen_name: rawData.name || '',
  raw_input: rawData.text || (rawData.audio_id ? 'Voice note' : rawData.image_id ? 'Image' : 'Unknown'),
  multimodal_urls: {
    image_url: rawData.image_id ? 'https://graph.facebook.com/v19.0/' + rawData.image_id : null,
    audio_url: rawData.audio_id ? 'https://graph.facebook.com/v19.0/' + rawData.audio_id : null
  },
  ai_analysis: {
    translated_description: ai.translated_description,
    domain: ai.domain,
    issue_type: ai.issue_type,
    sentiment_score: ai.sentiment_score,
    panic_flag: ai.panic_flag,
    location_hint: ai.location_hint || '',
    needs_photo: ai.needs_photo
  },
  location: {
    provided_text: rawData.text || null,
    latitude: null,
    longitude: null,
    location_hint: ai.location_hint || ''
  },
  embed_text: ai.translated_description
};

// Save session to Upstash with 1 hour TTL
const sessionKey = 'civix_session_' + rawData.phone;
const sessionData = {
  phase: 'awaiting_location',
  partial_pulse: partialPulse,
  created_at: new Date().toISOString()
};

try {
  await $http.request({
    method: 'SET',
    url: `${UPSTASH_URL}/set/${sessionKey}/EX/3600`,
    headers: { 'Authorization': `Bearer ${UPSTASH_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(JSON.stringify(sessionData))
  });
} catch(e) {
  // Fallback — try simpler set
  try {
    await $http.request({
      method: 'POST',
      url: `${UPSTASH_URL}/set/${sessionKey}`,
      headers: { 'Authorization': `Bearer ${UPSTASH_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ value: JSON.stringify(sessionData) })
    });
  } catch(e2) {}
}

return [{ json: { ...partialPulse, chat_action: 'ask_location' } }];

