const incoming = $('Extract Message Data').first().json;
const existing = $input.first().json?.fields || null;

const newText = incoming.text || null;
const newLat = incoming.latitude || null;
const newLon = incoming.longitude || null;
const newImage = incoming.image_id ? 'https://graph.facebook.com/v19.0/' + incoming.image_id : null;

if (!existing) {
  return [{ json: {
    phone: incoming.phone,
    translated_description: newText || 'Pending',
    latitude: newLat,
    longitude: newLon,
    image_url: newImage,
    raw_input: newText || 'start',
    stage: 'INIT',
    status: 'OPEN',
    created_at: new Date().toISOString(),
    mode: 'create'
  }}];
}

const raw_input = (existing.raw_input || '') + '\n---\n' + (newText || (newImage ? 'image' : 'location'));

const translated_description = existing.translated_description || newText;
const latitude = existing.latitude || newLat;
const longitude = existing.longitude || newLon;
const image_url = existing.image_url || newImage;

let stage = 'INIT';
if (!latitude || !longitude) stage = 'WAITING_LOCATION';
else if (!image_url) stage = 'WAITING_PHOTO';
else stage = 'COMPLETE';

return [{ json: {
  id: $input.first().json.id,
  phone: existing.phone,
  translated_description: translated_description || 'Pending',
  latitude,
  longitude,
  image_url,
  raw_input,
  stage,
  updated_at: new Date().toISOString(),
  mode: 'update'
}}];

const d = $input.first().json;
const missing = [];
if (!d.latitude || !d.longitude) missing.push('location');
if (!d.image_url) missing.push('photo');
return [{ json: { ...d, missing_fields: missing } }];
